// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "./DIDRegistry.sol";

contract CredentialStore is Initializable, AccessControlUpgradeable {
    DIDRegistry public didRegistry;

    struct Credential {
        bytes32 docHash;        // SHA-256 du document
        string cid;             // IPFS CID du payload (document + signature)
        address issuer;
        address holder;
        uint256 issuedAt;
        bool revoked;
        bool verified;          // statut retourné par l’IA / oracle
        uint256 verifiedAt;
    }

    mapping(bytes32 => Credential) public credentials; // docHash => Credential
    bytes32[] public allCredentialHashes;

    event CredentialIssued(bytes32 indexed docHash, string cid, address issuer, address holder);
    event CredentialRevoked(bytes32 indexed docHash);
    event CredentialVerified(bytes32 indexed docHash, bool verified, uint256 timestamp);

    function initialize(address _didRegistry) public initializer {
        __AccessControl_init();
        didRegistry = DIDRegistry(_didRegistry);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    modifier onlyIssuer() {
        require(didRegistry.isIssuer(msg.sender), "Not an issuer");
        _;
    }

    function issueCredential(
        bytes32 _docHash,
        string memory _cid,
        address _holder
    ) external onlyIssuer {
        require(credentials[_docHash].issuer == address(0), "Credential already exists");
        credentials[_docHash] = Credential({
            docHash: _docHash,
            cid: _cid,
            issuer: msg.sender,
            holder: _holder,
            issuedAt: block.timestamp,
            revoked: false,
            verified: false,
            verifiedAt: 0
        });
        allCredentialHashes.push(_docHash);
        emit CredentialIssued(_docHash, _cid, msg.sender, _holder);
    }

    function revokeCredential(bytes32 _docHash) external {
        require(msg.sender == credentials[_docHash].issuer || hasRole(DEFAULT_ADMIN_ROLE, msg.sender), "Not authorized");
        require(!credentials[_docHash].revoked, "Already revoked");
        credentials[_docHash].revoked = true;
        emit CredentialRevoked(_docHash);
    }

    function setVerificationStatus(bytes32 _docHash, bool _verified) external onlyRole(DEFAULT_ADMIN_ROLE) {
        credentials[_docHash].verified = _verified;
        credentials[_docHash].verifiedAt = block.timestamp;
        emit CredentialVerified(_docHash, _verified, block.timestamp);
    }

    function getCredential(bytes32 _docHash) external view returns (Credential memory) {
        return credentials[_docHash];
    }
}

contracts/DIDRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";

contract DIDRegistry is Initializable, AccessControlUpgradeable {
    bytes32 public constant ISSUER_ROLE = keccak256("ISSUER_ROLE");

    struct DID {
        address owner;
        bytes hybridPublicKey; // ML-DSA-65 + HQC-128 concatenated
        uint256 registeredAt;
        bool active;
    }

    mapping(address => DID) public dids;
    address[] public allDIDs;

    event DIDRegistered(address indexed owner, bytes hybridPublicKey, uint256 timestamp);
    event DIDDeactivated(address indexed owner);

    function initialize() public initializer {
        __AccessControl_init();
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    function registerDID(bytes memory _hybridPublicKey) external {
        require(!dids[msg.sender].active, "DID already active");
        dids[msg.sender] = DID(msg.sender, _hybridPublicKey, block.timestamp, true);
        allDIDs.push(msg.sender);
        emit DIDRegistered(msg.sender, _hybridPublicKey, block.timestamp);
    }

    function deactivateDID() external {
        require(dids[msg.sender].active, "DID not active");
        dids[msg.sender].active = false;
        emit DIDDeactivated(msg.sender);
    }

    function grantIssuerRole(address account) external onlyRole(DEFAULT_ADMIN_ROLE) {
        grantRole(ISSUER_ROLE, account);
    }

    function isIssuer(address account) public view returns (bool) {
        return hasRole(ISSUER_ROLE, account) && dids[account].active;
    }
}

contracts/UserRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract UserRegistry {
    // Rôles (bitmask)
    uint256 public constant ROLE_ISSUER = 1 << 0;  // 1
    uint256 public constant ROLE_HOLDER = 1 << 1; // 2
    uint256 public constant ROLE_VERIFIER = 1 << 2; // 4

    struct User {
        bytes mldsaPublicKey;    // ML-DSA-65 public key (obligatoire pour issuer, optionnel pour holder/verifier)
        bytes mlkemPublicKey;    // optionnel, pour chiffrement
        string metadataCID;      // CID IPFS du DID / profil
        uint256 roles;           // combinaison de ROLE_*
        bool active;
        uint256 registeredAt;
        uint256 updatedAt;
    }

    mapping(address => User) public users;
    address[] public userList;

    event UserRegistered(address indexed user, uint256 roles, uint256 timestamp);
    event UserUpdated(address indexed user, uint256 roles, uint256 timestamp);
    event UserRevoked(address indexed user, uint256 timestamp);

    modifier onlyActiveUser(address _user) {
        require(users[_user].active, "User not active");
        _;
    }

    modifier onlySelfOrAdmin(address _user) {
        require(msg.sender == _user || msg.sender == address(this), "Not authorized");
        _;
    }

    function registerUser(
        bytes calldata _mldsaPublicKey,
        bytes calldata _mlkemPublicKey,
        string calldata _metadataCID,
        uint256 _roles
    ) external {
        require(!users[msg.sender].active, "User already active");
        require(_roles != 0, "At least one role required");
        // Si le rôle émetteur est demandé, la clé ML-DSA est obligatoire
        if ((_roles & ROLE_ISSUER) != 0) {
            require(_mldsaPublicKey.length > 0, "ML-DSA key required for issuer");
        }

        users[msg.sender] = User({
            mldsaPublicKey: _mldsaPublicKey,
            mlkemPublicKey: _mlkemPublicKey,
            metadataCID: _metadataCID,
            roles: _roles,
            active: true,
            registeredAt: block.timestamp,
            updatedAt: block.timestamp
        });
        userList.push(msg.sender);
        emit UserRegistered(msg.sender, _roles, block.timestamp);
    }

    function updateUser(
        bytes calldata _mldsaPublicKey,
        bytes calldata _mlkemPublicKey,
        string calldata _metadataCID,
        uint256 _roles
    ) external onlyActiveUser(msg.sender) {
        require(_roles != 0, "At least one role required");
        if ((_roles & ROLE_ISSUER) != 0) {
            require(_mldsaPublicKey.length > 0, "ML-DSA key required for issuer");
        }
        User storage u = users[msg.sender];
        if (_mldsaPublicKey.length > 0) u.mldsaPublicKey = _mldsaPublicKey;
        if (_mlkemPublicKey.length > 0) u.mlkemPublicKey = _mlkemPublicKey;
        if (bytes(_metadataCID).length > 0) u.metadataCID = _metadataCID;
        u.roles = _roles;
        u.updatedAt = block.timestamp;
        emit UserUpdated(msg.sender, _roles, block.timestamp);
    }

    function revokeUser(address _user) external onlySelfOrAdmin(_user) {
        require(users[_user].active, "User already revoked");
        users[_user].active = false;
        users[_user].updatedAt = block.timestamp;
        emit UserRevoked(_user, block.timestamp);
    }

    function isIssuer(address _user) external view returns (bool) {
        return users[_user].active && ((users[_user].roles & ROLE_ISSUER) != 0);
    }

    function isHolder(address _user) external view returns (bool) {
        return users[_user].active && ((users[_user].roles & ROLE_HOLDER) != 0);
    }

    function isVerifier(address _user) external view returns (bool) {
        return users[_user].active && ((users[_user].roles & ROLE_VERIFIER) != 0);
    }

    function getUser(address _user) external view returns (User memory) {
        return users[_user];
    }

    function getAllUsers() external view returns (address[] memory) {
        return userList;
    }
}

contracts/VerificationOracle.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "./CredentialStore.sol";

contract VerificationOracle is Initializable, AccessControlUpgradeable {
    CredentialStore public credentialStore;

    struct Request {
        address requester;
        bytes32 docHash;
        uint256 requestedAt;
        bool resolved;
        bool isValid;
        string proofCID;      // IPFS CID du résultat (AI + heatmap + signature)
        address resolver;
        uint256 resolvedAt;
    }

    mapping(uint256 => Request) public requests;
    mapping(bytes32 => uint256[]) public credentialRequests;
    uint256 public totalRequests;

    address public oracle;
    address public pendingOracle;

    event VerificationRequested(uint256 indexed requestId, bytes32 indexed docHash, address indexed requester, uint256 timestamp);
    event VerificationResolved(uint256 indexed requestId, bytes32 indexed docHash, bool isValid, string proofCID, address resolver, uint256 timestamp);
    event OracleUpdated(address indexed oldOracle, address indexed newOracle);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers(); // pour upgradeable
    }

    function initialize(address _credentialStore, address _oracle) public initializer {
        __AccessControl_init();
        require(_credentialStore != address(0), "Invalid CredentialStore");
        require(_oracle != address(0), "Oracle address required");
        credentialStore = CredentialStore(_credentialStore);
        oracle = _oracle;
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    modifier onlyOracle() {
        require(msg.sender == oracle, "Only oracle can call");
        _;
    }

    function requestVerification(bytes32 _docHash) external returns (uint256) {
        require(_docHash != bytes32(0), "Invalid docHash");
        uint256 requestId = totalRequests;
        requests[requestId] = Request({
            requester: msg.sender,
            docHash: _docHash,
            requestedAt: block.timestamp,
            resolved: false,
            isValid: false,
            proofCID: "",
            resolver: address(0),
            resolvedAt: 0
        });
        credentialRequests[_docHash].push(requestId);
        totalRequests++;
        emit VerificationRequested(requestId, _docHash, msg.sender, block.timestamp);
        return requestId;
    }

    function submitVerificationResult(
        uint256 _requestId,
        bool _isValid,
        string memory _proofCID
    ) external onlyOracle {
        require(_requestId < totalRequests, "Request does not exist");
        require(!requests[_requestId].resolved, "Already resolved");
        Request storage req = requests[_requestId];
        req.resolved = true;
        req.isValid = _isValid;
        req.proofCID = _proofCID;
        req.resolver = msg.sender;
        req.resolvedAt = block.timestamp;

        // Mise à jour du statut dans CredentialStore
        credentialStore.setVerificationStatus(req.docHash, _isValid);

        emit VerificationResolved(_requestId, req.docHash, _isValid, _proofCID, msg.sender, block.timestamp);
    }

    function getVerificationStatus(uint256 _requestId) external view returns (bool resolved, bool isValid, uint256 requestedAt, uint256 resolvedAt, string memory proofCID) {
        Request storage req = requests[_requestId];
        return (req.resolved, req.isValid, req.requestedAt, req.resolvedAt, req.proofCID);
    }

    function getCredentialVerifications(bytes32 _docHash) external view returns (uint256[] memory) {
        return credentialRequests[_docHash];
    }

    // --- Gestion du changement d'oracle ---
    function proposeNewOracle(address _newOracle) external onlyOracle {
        require(_newOracle != address(0), "Invalid address");
        pendingOracle = _newOracle;
    }

    function acceptOracle() external {
        require(msg.sender == pendingOracle, "Only pending oracle can accept");
        emit OracleUpdated(oracle, pendingOracle);
        oracle = pendingOracle;
        pendingOracle = address(0);
    }
}

contracts/ZKPresentation.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";

/**
 * @title ZKPresentation
 * @notice Gère les preuves à divulgation nulle (Zero-Knowledge) pour les Presentation Credentials.
 * @dev Supporte la vérification on-chain via un verifier configurable (ex: Groth16, Plonk).
 *      Les preuves sont stockées off-chain, seul leur hash est conservé on-chain.
 */
contract ZKPresentation is Initializable, AccessControlUpgradeable {
    bytes32 public constant VERIFIER_ROLE = keccak256("VERIFIER_ROLE");

    // Guard anti-reentrance maison (compatible upgradeable)
    uint256 private _reentrancyStatus;

    /// @notice Structure d'une présentation ZK
    struct Presentation {
        bytes32 presentationId;   // Identifiant unique de la présentation
        bytes32 credentialHash;   // Hash du credential concerné (docHash)
        address prover;           // Personne qui prouve (holder)
        address verifier;         // Entité qui vérifie (peut être un oracle ou contrat)
        bytes32 publicInputsHash; // Hash des inputs publics (ex: age>18, pays, etc.)
        bytes32 proofHash;        // Hash de la preuve ZK (stockée off-chain)
        uint256 timestamp;
        bool verified;
        bool revoked;
        string metadataCID;       // CID IPFS contenant les détails de la preuve (optionnel)
    }

    mapping(bytes32 => Presentation) public presentations;
    mapping(bytes32 => bytes32[]) public credentialPresentations; // credentialHash -> liste presentationIds
    mapping(address => bytes32[]) public proverPresentations;      // prover -> liste presentationIds

    bytes32[] public allPresentationIds;

    address public zkVerifier;    // Adresse du contrat verifier (ex: Groth16Verifier)

    event PresentationCreated(
        bytes32 indexed presentationId,
        bytes32 indexed credentialHash,
        address indexed prover,
        bytes32 publicInputsHash,
        string metadataCID,
        uint256 timestamp
    );

    event PresentationVerified(
        bytes32 indexed presentationId,
        bytes32 indexed credentialHash,
        bool success,
        address verifier,
        uint256 timestamp
    );

    event PresentationRevoked(
        bytes32 indexed presentationId,
        address revoker,
        uint256 timestamp
    );

    event ZKVerifierUpdated(address indexed oldVerifier, address indexed newVerifier);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(address _zkVerifier) public initializer {
        __AccessControl_init();
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);

        // Initialiser le guard anti-reentrance
        _reentrancyStatus = 1;

        if (_zkVerifier != address(0)) {
            zkVerifier = _zkVerifier;
            _grantRole(VERIFIER_ROLE, _zkVerifier);
        }
    }

    // Modifier anti-reentrance maison
    modifier nonReentrant() {
        require(_reentrancyStatus != 2, "ReentrancyGuard: reentrant call");
        _reentrancyStatus = 2;
        _;
        _reentrancyStatus = 1;
    }

    modifier onlyVerifier() {
        require(hasRole(VERIFIER_ROLE, msg.sender), "Caller is not a verifier");
        _;
    }

    /**
     * @notice Crée une nouvelle présentation (sans vérification immédiate)
     * @param _credentialHash Hash du credential concerné
     * @param _publicInputsHash Hash des inputs publics (pour lier la preuve)
     * @param _metadataCID CID IPFS contenant les détails de la preuve (optionnel)
     * @return presentationId Identifiant unique généré
     */
    function createPresentation(
        bytes32 _credentialHash,
        bytes32 _publicInputsHash,
        string memory _metadataCID
    ) external nonReentrant returns (bytes32) {
        require(_credentialHash != bytes32(0), "Invalid credential hash");

        bytes32 presentationId = keccak256(abi.encodePacked(
            _credentialHash,
            msg.sender,
            _publicInputsHash,
            block.timestamp,
            block.prevrandao
        ));

        require(presentations[presentationId].timestamp == 0, "Presentation already exists");

        presentations[presentationId] = Presentation({
            presentationId: presentationId,
            credentialHash: _credentialHash,
            prover: msg.sender,
            verifier: address(0),
            publicInputsHash: _publicInputsHash,
            proofHash: bytes32(0),
            timestamp: block.timestamp,
            verified: false,
            revoked: false,
            metadataCID: _metadataCID
        });

        credentialPresentations[_credentialHash].push(presentationId);
        proverPresentations[msg.sender].push(presentationId);
        allPresentationIds.push(presentationId);

        emit PresentationCreated(
            presentationId,
            _credentialHash,
            msg.sender,
            _publicInputsHash,
            _metadataCID,
            block.timestamp
        );

        return presentationId;
    }

    /**
     * @notice Soumet une preuve ZK pour une présentation (vérification on-chain)
     * @param _presentationId Identifiant de la présentation
     * @param _proof Données de la preuve (format dépendant du verifier)
     * @param _publicInputs Inputs publics pour la vérification
     * @return success Vrai si la preuve est valide
     */
    function submitProofAndVerify(
        bytes32 _presentationId,
        bytes calldata _proof,
        uint256[] calldata _publicInputs
    ) external nonReentrant returns (bool) {
        Presentation storage pres = presentations[_presentationId];
        require(pres.timestamp != 0, "Presentation does not exist");
        require(!pres.verified, "Already verified");
        require(!pres.revoked, "Presentation revoked");
        require(msg.sender == pres.prover, "Only prover can submit proof");

        // Vérifier que les inputs publics correspondent au hash stocké
        bytes32 computedHash = keccak256(abi.encodePacked(_publicInputs));
        require(computedHash == pres.publicInputsHash, "Public inputs mismatch");

        // Vérification on-chain via le verifier configuré
        bool isValid = _verifyProof(_proof, _publicInputs);

        if (isValid) {
            pres.verified = true;
            pres.verifier = address(this);
            pres.proofHash = keccak256(_proof);
        }

        emit PresentationVerified(
            _presentationId,
            pres.credentialHash,
            isValid,
            msg.sender,
            block.timestamp
        );

        return isValid;
    }

    /**
     * @notice Vérification interne (appelle le contrat verifier ou une precompile)
     * @dev À adapter selon le système ZK utilisé (Groth16, Plonk, etc.)
     */
    function _verifyProof(bytes calldata _proof, uint256[] calldata _publicInputs) internal view returns (bool) {
        require(zkVerifier != address(0), "ZK verifier not set");

        (bool success, bytes memory result) = zkVerifier.staticcall(
            abi.encodeWithSignature("verifyProof(bytes,uint256[])", _proof, _publicInputs)
        );
        require(success, "Verifier call failed");
        return abi.decode(result, (bool));
    }

    /**
     * @notice Vérification par un oracle (sans preuve on-chain)
     * @dev Utile si la vérification est trop coûteuse ou si le verifier n'est pas déployé
     */
    function verifyByOracle(
        bytes32 _presentationId,
        bool _isValid,
        bytes32 _proofHash,
        string memory _proofCID
    ) external onlyVerifier {
        Presentation storage pres = presentations[_presentationId];
        require(pres.timestamp != 0, "Presentation does not exist");
        require(!pres.verified, "Already verified");
        require(!pres.revoked, "Presentation revoked");

        pres.verified = _isValid;
        pres.verifier = msg.sender;
        pres.proofHash = _proofHash;
        pres.metadataCID = _proofCID;

        emit PresentationVerified(
            _presentationId,
            pres.credentialHash,
            _isValid,
            msg.sender,
            block.timestamp
        );
    }

    /**
     * @notice Révoque une présentation (par le prover ou admin)
     */
    function revokePresentation(bytes32 _presentationId) external {
        Presentation storage pres = presentations[_presentationId];
        require(pres.timestamp != 0, "Presentation does not exist");
        require(!pres.revoked, "Already revoked");
        require(msg.sender == pres.prover || hasRole(DEFAULT_ADMIN_ROLE, msg.sender), "Not authorized");

        pres.revoked = true;
        emit PresentationRevoked(_presentationId, msg.sender, block.timestamp);
    }

    /**
     * @notice Met à jour l'adresse du verifier ZK
     */
    function setZKVerifier(address _newVerifier) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_newVerifier != address(0), "Invalid address");
        address old = zkVerifier;
        if (old != address(0)) {
            revokeRole(VERIFIER_ROLE, old);
        }
        zkVerifier = _newVerifier;
        grantRole(VERIFIER_ROLE, _newVerifier);
        emit ZKVerifierUpdated(old, _newVerifier);
    }

    /**
     * @notice Récupère les détails d'une présentation
     */
    function getPresentation(bytes32 _presentationId) external view returns (Presentation memory) {
        return presentations[_presentationId];
    }

    /**
     * @notice Liste les presentations d'un credential
     */
    function getCredentialPresentations(bytes32 _credentialHash) external view returns (bytes32[] memory) {
        return credentialPresentations[_credentialHash];
    }

    /**
     * @notice Liste les presentations d'un prover
     */
    function getProverPresentations(address _prover) external view returns (bytes32[] memory) {
        return proverPresentations[_prover];
    }
}

